#include<bits/stdc++.h>
using namespace std;
int k,a,b,c,cnt,x,z;
int main(){
	cin>>k>>a>>b>>c;
	for(int i=1;i<=k;i++){
		cin>>x;
		if(x<=10){
			cnt=x*a;
		}else if(x<=100){
			cnt=10*a+(x-10)*b;
		}else{
			cnt=10*a+90*b+(x-100)*c;
		}
		z+=cnt;
	}
	cout<<z;
    return 0;
}
